	planContainer = null;
	planTUI = null;
	lastActivityFeedText = "";
	ctx.ui.setHeader(undefined);
}

function setupPlanPanel(goal: string, stepLabels: string[], ctx: { ui: { setHeader: (f: any) => void } }): void {
	planState = {
		goal,
		steps: stepLabels.map((label, i) => ({
			label,
			completed: false,
			active: i === 0,
		})),
		startTime: Date.now(),
	};
	ctx.ui.setHeader((tui: TUI, theme: any) => buildPlanPanel(tui, theme));
	startPlanTimer();
