// ── Helpers for consistent box rendering ──
function specialistName(s: string): string {
	return s.charAt(0).toUpperCase() + s.slice(1);
}
function getToolBoxWidth(name: string): number {
	return 3 + name.length + 1 + Math.max(0, BOX_INNER_WIDTH - name.length) + 1;
}
function wrapLinesInBox(lines: string[], boxWidth: number, theme: any): string {
	const out: string[] = [];
	for (const line of lines) {
		const clean = line.replace(/\x1b\[[0-9;]*m/g, "");
		const padded = clean.length > boxWidth - 4
			? clean.slice(0, boxWidth - 4)
			: clean + " ".repeat(boxWidth - 4 - clean.length);
		out.push(`│ ${padded} │`);
	}
	out.push(`╰${("─").repeat(boxWidth - 2)}╯`);
	return out.join("\n");
}

// ── Render: what shows when tool is invoked ──
renderCall(args, theme, _context) {
	if (args.specialist) {
		const name = specialistName(args.specialist);
		const boxWidth = getToolBoxWidth(name);
		const inner = `${name} ${("─").repeat(Math.max(0, BOX_INNER_WIDTH - name.length))}`;
		return new Text(theme.fg("toolTitle", `╭─ ${inner}╮`), 0, 0);
	}
	if (args.tasks) {
		const names = args.tasks.map((t: any) => t.specialist).join(", ");
		return new Text(theme.fg("toolTitle", theme.bold(`→ parallel [${args.tasks.length}] `)) + theme.fg("dim", names), 0, 0);
	}
	if (args.steps) {
		const names = args.steps.map((s: any) => s.specialist).join(" → ");
		return new Text(theme.fg("toolTitle", theme.bold(`→ chain `)) + theme.fg("dim", names), 0, 0);
	}
	return new Text(theme.fg("toolTitle", theme.bold(`→ `)) + theme.fg("accent", args.specialist || "?"), 0, 0);
},

