// ── Helper: wrap lines in a bordered box ──
function wrapInBox(lines: string[], boxWidth: number, theme: any): string {
	const out: string[] = [];
	for (const line of lines) {
		const clean = line.replace(/\x1b\[[0-9;]*m/g, "");
		const padded = clean.length > boxWidth - 4
			? clean.slice(0, boxWidth - 4)
			: clean + " ".repeat(boxWidth - 4 - clean.length);
		out.push(`│ ${padded} │`);
	}
	out.push(`╰${("─").repeat(boxWidth - 2)}╯`);
	return out.join("\n");
}

// ── Helper: get specialist name from params/details ──
function getSpecName(params: any, details: any): string {
	if (params?.specialist) {
		return params.specialist.charAt(0).toUpperCase() + params.specialist.slice(1);
	}
	if (details?.specialist) {
		return details.specialist;
	}
	return "";
}

// ── Helper: compute tool block box width ──
function boxWidthFor(name: string): number {
	if (!name) return 0;
	return 3 + name.length + 1 + Math.max(0, BOX_INNER_WIDTH - name.length) + 1;
}

// ── Render: what shows during/after execution ──
renderResult(result, { isPartial, expanded }, theme, context) {
	const details = result.details as any;
	const ctxParams = (context as any)?.params as Record<string, any> | undefined;
	const content = result.content?.[0];
	const text = content?.type === "text" ? content.text : "";

	const specName = getSpecName(ctxParams, details);
	const bWidth = boxWidthFor(specName);

	if (isPartial) {
		if (text && bWidth > 0) {
			return new Text(theme.fg("warning", wrapInBox(text.split("\n"), bWidth, theme)), 0, 0);
		}
		if (details?.specialist && bWidth > 0) {
			return new Text(theme.fg("warning", wrapInBox([`⠋ ${details.specialist}...`], bWidth, theme)), 0, 0);
		}
		if (bWidth > 0) {
			return new Text(theme.fg("warning", wrapInBox(["⠋ working..."], bWidth, theme)), 0, 0);
		}
		return new Text(theme.fg("warning", "⠋ working..."), 0, 0);
	}

	// Single mode — show activity feed in box (all ✓, never collapses)
	if (details?.specialist && bWidth > 0) {
		const feedText = lastActivityFeedText || text || `✓ ${details.specialist}`;
		return new Text(theme.fg("success", wrapInBox(feedText.split("\n"), bWidth, theme)), 0, 0);
	}

	// Parallel mode
	if (details?.results) {
		const ok = details.results.filter((r: any) => !r.error).length;
		const total = details.results.length;
		const summary = `✓ ${ok}/${total} completed`;
		const lines: string[] = [summary];
		if (expanded) {
			for (const r of details.results) {
				const icon = r.error ? "✗" : "✓";
				lines.push(`${icon} ${r.specialist}`);
			}
		}
		const pBoxWidth = Math.max(summary.length + 4, 30);
		return new Text(theme.fg("success", wrapInBox(lines, pBoxWidth, theme)), 0, 0);
	}

	// Chain mode
	if (details?.steps) {
		const summary = `✓ ${details.steps} steps completed`;
		const lines: string[] = [summary];
		if (expanded && text) {
			for (const line of text.split("\n").slice(0, 10)) {
				lines.push(`  ${line}`);
			}
		}
		const cBoxWidth = Math.max(summary.length + 4, 30);
		return new Text(theme.fg("success", wrapInBox(lines, cBoxWidth, theme)), 0, 0);
	}

	return new Text(theme.fg("success", "✓ done"), 0, 0);
},

