/**
 * ORCHESTRATOR EXTENSION — Architecture & Debugging Guide
 * 
 * This extension turns pi into a pure orchestrator that delegates all work
 * to specialist subagents. The main agent never touches files directly.
 * 
 * COMPONENTS:
 * 1. Activity Feed System (lines 40-260)
 *    - Tracks subagent progress for real-time UX display
 *    - Zero token cost (onUpdate not persisted)
 *    - State: ActivityFeedState { goal, steps, currentStep }
 *    - Functions: createActivityFeed, parseTextForFeed, renderActivityFeed
 *    
 * 2. Specialist Definitions (lines 280-420)
 *    - scout, coder, reviewer, researcher, writer
 *    - Each has: name, tools[], model?, systemPrompt
 *    - systemPrompt includes ACTIVITY_FEED_INSTRUCTION for plan output
 *    
 * 3. In-Process Subagent Runner (lines 440-560)
 *    - runSubagent(): creates isolated AgentSession
 *    - Uses parent's modelRegistry for API key inheritance
 *    - Subscribes to session events → updates activity feed
 *    
 * 4. Tool Handlers (lines 580-700)
 *    - delegate(): single specialist
 *    - parallel(): multiple specialists simultaneously
 *    - chain(): sequential with context passing
 * 
 * COMMON ISSUES:
 * - "No API key found" → Check modelRegistry inheritance (line 460)
 * - Empty output → Check specialist.tools includes needed tools
 * - Feed not updating → Check event types in session.subscribe()
 * - Steps not parsing → Check ## Goal / ## Steps format in prompt
 * 
 * ACTIVITY FEED FLOW:
 * 1. Subagent starts → parseTextForFeed extracts goal + steps
 * 2. tool_call event → addSubstep (auto-detects tool type)
 * 3. tool_result event → completeLastSubstep
 * 4. message_end event → completeCurrentStep, advance to next
 * 5. renderActivityFeed → formats for UI display
 */

import { getModel } from "@earendil-works/pi-ai";
import {
	AuthStorage,
	createAgentSession,
	createExtensionRuntime,
	DefaultResourceLoader,
	type ExtensionAPI,
	getAgentDir,
	ModelRegistry,
	type ResourceLoader,
	SessionManager,
} from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { Container, type Component, Text, type TUI } from "@earendil-works/pi-tui";
import { shortenLabel } from "./token-saver.ts";
import { appendFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";

const DEBUG_LOG_DIR = "/tmp/orchestrator-debug";
try { mkdirSync(DEBUG_LOG_DIR, { recursive: true }); } catch {}
const DEBUG_LOG = join(DEBUG_LOG_DIR, `orchestrator-${Date.now()}.log`);

function debugLog(msg: string, data?: any): void {
	const line = data ? `[${new Date().toISOString()}] ${msg} ${JSON.stringify(data)}` : `[${new Date().toISOString()}] ${msg}`;
	try { appendFileSync(DEBUG_LOG, line + "\n"); } catch {}
}

// ============================================================================
// Config
// ============================================================================

/**
 * Module-level orchestrator activity state.
 * Persists across multiple delegate/parallel/chain calls in a session.
 * Reset on new session via before_agent_start handler.
 */
let orchestratorActivity: OrchestratorActivity | null = null;
let orchestratorGoal: string = "";

function getOrchestratorActivity(taskDescription?: string): OrchestratorActivity {
	// Create fresh activity for each new tool call to avoid stale state
	if (!orchestratorActivity) {
		orchestratorActivity = createOrchestratorActivity();
	}
	if (taskDescription && !orchestratorGoal) {
		orchestratorGoal = shortenLabel(taskDescription);
	}
	return orchestratorActivity;
}

/** Reset orchestrator activity (called at start of each tool execute) */
function resetOrchestratorActivity(): void {
	orchestratorActivity = createOrchestratorActivity();
	orchestratorGoal = "";
	lastActivityFeedText = "";
}

const MAX_PARALLEL = 4;
const OUTPUT_CAP = 30_000; // bytes per subagent output fed back to main
const BOX_INNER_WIDTH = 52; // inner content width for tool block boxes

// ============================================================================
// Plan Panel — persistent header widget (setHeader)
// ============================================================================

/**
 * Plan panel state: the goal, steps, and timing for the Orchestration Plan header.
 * Set when delegate/parallel/chain is called. Cleared on before_agent_start.
 */
let planState: {
	goal: string;
	steps: Array<{ label: string; completed: boolean; active: boolean }>;
	startTime: number;
} | null = null;

let planContainer: Container | null = null;
let planTimer: ReturnType<typeof setInterval> | null = null;
let planTUI: TUI | null = null;

/**
 * Last rendered activity feed text.
 * Stored so renderResult can show it on final (non-partial) render.
 */
let lastActivityFeedText: string = "";

function buildPlanPanel(tui: TUI, theme: any): Container {
	// Reuse existing container so timer updates affect the SAME instance the TUI holds
	if (!planContainer) {
		planContainer = new Container();
	}
	planTUI = tui;
	renderPlanPanel();
	return planContainer;
}

function renderPlanPanel(): void {
	if (!planContainer || !planState) return;
	const { goal, steps, startTime } = planState;
	const elapsed = Date.now() - startTime;
	const elapsedStr = formatDuration(elapsed);

	const total = steps.length;
	const completed = steps.filter((s) => s.completed).length;

	const boxWidth = Math.max(goal.length + 4, 34);
	const padding = boxWidth - 4;
	const truncated = goal.length > padding ? goal.slice(0, padding - 3) + "..." : goal;
	const pad = padding - truncated.length;

	const dots = steps.map((s) => s.completed ? "●" : s.active ? "●" : "○").join("");

	planContainer.clear();

	planContainer.addChild(new Text(`┌─ Orchestration Plan ${("─").repeat(Math.max(0, boxWidth - 21))}┐`, 0, 0));
	planContainer.addChild(new Text(`│ Goal: ${truncated}${(" ").repeat(pad)} │`, 0, 0));

	for (const step of steps) {
		const icon = step.completed ? "✓" : step.active ? "⠋" : "○";
		const label = step.label.length > padding ? step.label.slice(0, padding - 3) + "..." : step.label;
		planContainer.addChild(new Text(`│  ${icon} ${label}${(" ").repeat(Math.max(0, padding - label.length - 2))} │`, 0, 0));
	}

	planContainer.addChild(new Text(`│  ${dots} [${completed}/${total}]      •    Elapsed: ${elapsedStr}${(" ").repeat(Math.max(0, 6))} │`, 0, 0));
	planContainer.addChild(new Text(`└${("─").repeat(boxWidth)}┘`, 0, 0));
}

function updatePlanDisplay(): void {
	renderPlanPanel();
	if (planContainer) planContainer.invalidate();
	if (planTUI) planTUI.requestRender();
}

function startPlanTimer(): void {
	stopPlanTimer();
	planTimer = setInterval(() => {
		if (planState && planContainer) {
			updatePlanDisplay();
		} else {
			stopPlanTimer();
		}
	}, 1000);
}

function stopPlanTimer(): void {
	if (planTimer !== null) {
		clearInterval(planTimer);
		planTimer = null;
	}
}

function clearPlanPanel(ctx: { ui: { setHeader: (f: any) => void }; mode?: string }): void {
	stopPlanTimer();
	planState = null;
	planContainer = null;
	planTUI = null;
	lastActivityFeedText = "";
	if (ctx.mode === "tui") {
		ctx.ui.setHeader(undefined);
	}
}

function setupPlanPanel(goal: string, stepLabels: string[], ctx: { ui: { setHeader: (f: any) => void }; mode?: string }): void {
	planState = {
		goal,
		steps: stepLabels.map((label, i) => ({
			label,
			completed: false,
			active: i === 0,
		})),
		startTime: Date.now(),
	};
	if (ctx.mode === "tui") {
		ctx.ui.setHeader((tui: TUI, theme: any) => buildPlanPanel(tui, theme));
	}
	startPlanTimer();
	updatePlanDisplay();
}

function completePlanStep(ctx: { ui: { setHeader: (f: any) => void }; mode?: string }): void {
	if (!planState) return;
	const idx = planState.steps.findIndex((s) => s.active);
	if (idx >= 0) {
		planState.steps[idx].completed = true;
		planState.steps[idx].active = false;
	}
	const next = idx + 1;
	if (next < planState.steps.length) {
		planState.steps[next].active = true;
	}
	updatePlanDisplay();
}

// ============================================================================
// Orchestrator Activity — high-level progress view for user
// ============================================================================

/**
 * OrchestratorActivity — tracks overall task progress
 * 
 * This is the USER-FACING progress view. It shows:
 *   - Overall progress [N/M]
 *   - Current step with arrow →
 *   - Completed steps with checkmark ✓ and timing
 *   - Pending steps with circle ○
 * 
 * NO specialist names shown — just task progress.
 * 
 * Format:
 *   [3/6] → Create package.json (2m 15s)
 *     ✓ Read pi extensions docs (12s)
 *     ✓ Read CloakBrowser README (8s)
 *     ✓ Analyze API patterns (45s)
 *     → Create package.json
 *     ○ Write index.ts
 *     ○ Test extension
 */

interface OrchestratorStep {
	label: string;
	completed: boolean;
	startTime?: number;
	endTime?: number;
}

interface OrchestratorActivity {
	steps: OrchestratorStep[];
	currentStep: number;
	startTime: number;
}

function createOrchestratorActivity(): OrchestratorActivity {
	return {
		steps: [],
		currentStep: -1,
		startTime: Date.now(),
	};
}

function addOrchestratorStep(activity: OrchestratorActivity, label: string): void {
	const cleanLabel = shortenLabel(label);
	// Avoid duplicates
	if (activity.steps.some((s) => s.label === cleanLabel)) return;
	activity.steps.push({
		label: cleanLabel,
		completed: false,
		startTime: Date.now(),
	});
	if (activity.currentStep === -1) activity.currentStep = 0;
}

function completeOrchestratorStep(activity: OrchestratorActivity): void {
	if (activity.currentStep < 0 || activity.currentStep >= activity.steps.length) return;
	activity.steps[activity.currentStep].completed = true;
	activity.steps[activity.currentStep].endTime = Date.now();
	activity.currentStep++;
}

function formatDuration(ms: number): string {
	if (ms < 1000) return `${ms}ms`;
	const seconds = Math.floor(ms / 1000);
	if (seconds < 60) return `${seconds}s`;
	const minutes = Math.floor(seconds / 60);
	const remainingSeconds = seconds % 60;
	return remainingSeconds > 0 ? `${minutes}m ${remainingSeconds}s` : `${minutes}m`;
}

/**
 * Render the orchestrator activity feed.
 * 
 * Format:
 *   ┌─ Task ─────────────────────────────┐
 *   │ Task description here               │
 *   └────────────────────────────────────┘
 *   ●●●○○○ [3/6]
 *   ✓ Read pi extensions docs (12s)
 *   ✓ Read CloakBrowser README (8s)
 *   ⠋ Analyze API patterns...
 *   ○ Create package.json
 *   ○ Write index.ts
 *   ○ Test extension
 */
function renderOrchestratorActivity(activity: OrchestratorActivity, goal?: string): string {
	const lines: string[] = [];
	const total = activity.steps.length;
	const completed = activity.steps.filter((s) => s.completed).length;

	if (goal) {
		const boxWidth = Math.max(goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = goal.length > padding ? goal.slice(0, padding - 3) + "..." : goal;
		const pad = padding - truncated.length;
		lines.push(`┌─ Task ${"─".repeat(boxWidth - 7)}┐`);
		lines.push(`│ ${truncated}${" ".repeat(pad)} │`);
		lines.push(`└${"─".repeat(boxWidth - 2)}┘`);
	}

	const dots = activity.steps.map((s, i) => {
		if (s.completed) return "●";
		if (i === activity.currentStep) return "●";
		return "○";
	}).join("");
	lines.push(`${dots} [${completed}/${total}]`);

	for (let i = 0; i < total; i++) {
		const step = activity.steps[i];
		const isCurrent = i === activity.currentStep;

		if (step.completed) {
			const duration = step.startTime && step.endTime
				? formatDuration(step.endTime - step.startTime)
				: "";
			lines.push(`✓ ${step.label}${duration ? ` (${duration})` : ""}`);
		} else if (isCurrent) {
			lines.push(`⠋ ${step.label}...`);
		} else {
			lines.push(`○ ${step.label}`);
		}
	}

	return lines.join("\n");
}

/**
 * Render combined orchestrator + subagent progress.
 * Shows overall task progress with the current step's subtasks indented.
 */
function renderCombinedProgress(
	orchestratorActivity: OrchestratorActivity,
	specialistName: string,
	feedState: ActivityFeedState,
	goal?: string,
): string {
	const lines: string[] = [];
	const total = orchestratorActivity.steps.length;
	const completed = orchestratorActivity.steps.filter((s) => s.completed).length;

	// Boxed header with goal
	if (goal) {
		const boxWidth = Math.max(goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = goal.length > padding ? goal.slice(0, padding - 3) + "..." : goal;
		const pad = padding - truncated.length;
		lines.push(`┌─ Task ${"─".repeat(boxWidth - 7)}┐`);
		lines.push(`│ ${truncated}${" ".repeat(pad)} │`);
		lines.push(`└${"─".repeat(boxWidth - 2)}┘`);
	}

	// Progress dots
	const dots = orchestratorActivity.steps.map((s, i) => {
		if (s.completed) return "●";
		if (i === orchestratorActivity.currentStep) return "●";
		return "○";
	}).join("");
	lines.push(`${dots} [${completed}/${total}]`);

	// Steps list
	for (let i = 0; i < total; i++) {
		const step = orchestratorActivity.steps[i];
		const isCurrent = i === orchestratorActivity.currentStep;
		const isPending = !step.completed && !isCurrent;

		if (step.completed) {
			const duration = step.startTime && step.endTime
				? formatDuration(step.endTime - step.startTime)
				: "";
			lines.push(`✓ ${step.label}${duration ? ` (${duration})` : ""}`);
		} else if (isCurrent) {
			lines.push(`→ ${step.label}... [${specialistName}]`);
			// Show subagent's subtasks indented under current step
			if (feedState.steps.length > 0 && feedState.currentStep >= 0 && feedState.currentStep < feedState.steps.length) {
				const currentFeedStep = feedState.steps[feedState.currentStep];
				for (const sub of currentFeedStep.substeps) {
					lines.push(sub.completed ? `  ✓ ${sub.label}` : `  ⠋ ${sub.label}...`);
				}
			} else {
				lines.push(`  ⠋ Starting...`);
			}
		} else if (isPending) {
			lines.push(`○ ${step.label}`);
		}
	}

	return lines.join("\n");
}

// ============================================================================
// Activity Feed — tracks subagent progress for UX display
// ============================================================================

/**
 * Activity Feed State
 * 
 * Tracks the subagent's work progress for real-time UX display.
 * Updated via text deltas and tool calls from the subagent session.
 * 
 * Structure:
 *   goal: string           - One-line description of the task
 *   steps: Step[]          - Main steps (defined by subagent or parsed)
 *   currentStep: number    - Index of currently active step
 *   substeps: Substep[]    - Dynamic substeps under current main step
 * 
 * Parsing:
 *   - ## Goal\n<text> → sets goal
 *   - ## Steps\n- <text> → adds main steps
 *   - Tool calls (read/grep/bash) → adds substeps
 *   - message_end → marks current step complete
 * 
 * Display:
 *   ✓ = completed, → = in progress, ○ = pending
 *   Completed main steps show substep count: "✓ Step (N items)"
 *   Current step shows last 2 substeps
 */

interface Substep {
	label: string;
	completed: boolean;
}

interface Step {
	label: string;
	completed: boolean;
	substeps: Substep[];
}

interface ActivityFeedState {
	goal: string;
	steps: Step[];
	currentStep: number;
}

function createActivityFeed(): ActivityFeedState {
	return {
		goal: "",
		steps: [],
		currentStep: -1,
	};
}

/**
 * Parse subagent text output to extract goal and steps.
 * Called on each text_delta to update the feed incrementally.
 */
function parseTextForFeed(state: ActivityFeedState, text: string): void {
	const lines = text.split("\n");
	for (const line of lines) {
		const trimmed = line.trim();
		if (trimmed.startsWith("## Goal")) {
			// Next non-empty line is the goal
			state.goal = ""; // Will be set on next line
		} else if (trimmed.startsWith("## Steps")) {
			// Subsequent "- " lines are steps
		} else if (trimmed.startsWith("- ") && state.goal && state.steps.length === 0) {
			// First "- " after goal = first step
			addStep(state, trimmed.slice(2));
		} else if (trimmed.startsWith("- ") && state.steps.length > 0) {
			addStep(state, trimmed.slice(2));
		} else if (state.goal === "" && trimmed.length > 0 && !trimmed.startsWith("#")) {
			state.goal = trimmed;
		}
	}
}

function addStep(state: ActivityFeedState, label: string): void {
	// Avoid duplicates
	if (state.steps.some((s) => s.label === label)) return;
	state.steps.push({ label, completed: false, substeps: [] });
	if (state.currentStep === -1) state.currentStep = 0;
}

/**
 * Add a substep to the current main step.
 * Called when a tool_call event is detected.
 */
function addSubstep(state: ActivityFeedState, label: string): void {
	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
	const step = state.steps[state.currentStep];
	// Avoid duplicates
	if (step.substeps.some((s) => s.label === label)) return;
	step.substeps.push({ label, completed: false });
}

/**
 * Mark the current step's last substep as complete.
 */
function completeLastSubstep(state: ActivityFeedState): void {
	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
	const step = state.steps[state.currentStep];
	if (step.substeps.length > 0) {
		step.substeps[step.substeps.length - 1].completed = true;
	}
}

/**
 * Mark current step as complete, advance to next.
 */
function completeCurrentStep(state: ActivityFeedState): void {
	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
	// Complete any pending substeps
	for (const sub of state.steps[state.currentStep].substeps) {
		sub.completed = true;
	}
	state.steps[state.currentStep].completed = true;
	state.currentStep++;
}

/**
 * Auto-detect substep from tool call.
 * Maps tool names to human-readable labels.
 */
function toolCallToSubstep(toolName: string, input: any): string {
	switch (toolName) {
		case "read":
			return `Reading ${input?.path || "file"}`;
		case "bash":
			return `Running: ${(input?.command || "...").slice(0, 40)}`;
		case "grep":
			return `Searching: ${input?.pattern || "..."}`;
		case "find":
			return `Finding: ${input?.pattern || "..."}`;
		case "edit":
			return `Editing ${input?.path || "file"}`;
		case "write":
			return `Writing ${input?.path || "file"}`;
		default:
			return `Using ${toolName}`;
	}
}

/**
 * Render the subagent activity feed.
 * 
 * Cache-safe: only used in onUpdate (display-only), not persisted.
 * 
 * Format (indented under orchestrator):
 *   ✓ README.md (4s)
 *   ⠋ examples.md...
 *   ○ package.json
 * 
 * Shows ONLY current step's subtasks in chronological order.
 * Completed subtasks at top, current in middle, pending at bottom.
 */
function renderActivityFeed(name: string, state: ActivityFeedState): string {
	const lines: string[] = [];

	// If no steps yet, show starting
	if (state.steps.length === 0) {
		lines.push(`  ⠋ Starting...`);
		return lines.join("\n");
	}

	const total = state.steps.length;
	const completed = state.steps.filter((s) => s.completed).length;

	// Task box with goal
	if (state.goal) {
		const boxWidth = Math.max(state.goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = state.goal.length > padding ? state.goal.slice(0, padding - 3) + "..." : state.goal;
		const pad = padding - truncated.length;
		lines.push(`┌─ Task ${("─").repeat(Math.max(0, boxWidth - 7))}┐`);
		lines.push(`│ ${truncated}${(" ").repeat(pad)} │`);
		lines.push(`└${("─").repeat(Math.max(0, boxWidth - 2))}┘`);
	}

	// Progress dots
	const dots = state.steps.map((s, i) => {
		if (s.completed) return "●";
		if (i === state.currentStep) return "●";
		return "○";
	}).join("");
	lines.push(`${dots} [${completed}/${total}]`);

	// Steps list
	for (let i = 0; i < total; i++) {
		const step = state.steps[i];
		const isCurrent = i === state.currentStep;

		if (step.completed) {
			lines.push(`✓ ${step.label}`);
		} else if (isCurrent) {
			lines.push(`⠋ ${step.label}...`);
			// Show substeps indented under current step
			for (const sub of step.substeps) {
				lines.push(sub.completed ? `  ✓ ${sub.label}` : `  ⠋ ${sub.label}...`);
			}
		} else {
			lines.push(`○ ${step.label}`);
		}
	}

	return lines.join("\n");
}

// ============================================================================
// Compression — applied to ALL subagent output before returning to main agent
// ==============================================================================

const ANSI_RE = /\x1b\[[0-9;]*[a-zA-Z]/g;

/**
 * Compress subagent output for token savings.
 * 
 * Cache-safe: compression happens BEFORE output enters parent context.
 * Delegates to token-saver's compression logic for consistency.
 */
function compressOutput(output: string): string {
	let result = output;

	// Strip ANSI color codes
	result = result.replace(ANSI_RE, "");

	// Collapse triple+ blank lines
	result = result.replace(/\n{3,}/g, "\n\n");

	// Trim leading/trailing whitespace
	result = result.trim();

	return result;
}

// ============================================================================
// Subagent definitions — each specialist has a focused prompt
// ============================================================================

interface Specialist {
	name: string;
	tools: string[];
	model?: string;
	systemPrompt: string;
}

const TERSE_INSTRUCTION = `

## Reply Style: Terse (token savings)
- Reply in terse technical fragments
- No greetings, no hedging, no apologies
- No "Here's what I found:", just the answer
- One line per fact
- Code blocks > prose
- If you must explain, use 1-2 sentences max`;

const ACTIVITY_FEED_INSTRUCTION = `

## Activity Feed (IMPORTANT - for UX display)
At the start of your task, output your plan in this exact format:

## Goal
<one line describing the goal>

## Steps
- Step 1 description
- Step 2 description
- Step 3 description

As you complete each step, the system will track your progress automatically via tool calls.`;

const SPECIALISTS: Record<string, Specialist> = {
	scout: {
		name: "scout",
		tools: ["read", "bash"],
		systemPrompt: `You are a fast codebase scout. Investigate and return compressed findings.${ACTIVITY_FEED_INSTRUCTION}

Rules:
- Use grep/find to locate code, read key sections only
- Output structured findings another agent can use without re-reading files
- Be concise — your output feeds into a planner
- Reply in terse fragments. No filler, no hedging, no paragraphs

Output format:
## Files Found
(path + line ranges + what's there)

## Key Code
Critical types/functions/interfaces

## Dependencies
How pieces connect

## Recommendation
Which file to start with and why`,
	},

	coder: {
		name: "coder",
		tools: ["read", "bash", "edit", "write"],
		systemPrompt: `You are an implementation specialist. Execute a plan precisely.${ACTIVITY_FEED_INSTRUCTION}

Rules:
- Read files mentioned in the plan
- Make exactly the changes described — no extra changes
- ALWAYS use \`edit\` tool for file modifications — if exact-text match fails, retry with \`write\` (full file). NEVER use \`bash\` + \`sed\`/\`awk\`
- Verify changes compile/run
- Report what changed
- Reply in terse fragments. No filler

Output format:
## Completed
What was done.

## Files Changed
- path - what changed

## Verification
What you checked.`,
	},

	reviewer: {
		name: "reviewer",
		tools: ["read", "bash"],
		systemPrompt: `You are a senior code reviewer. Analyze for bugs, security, quality.${ACTIVITY_FEED_INSTRUCTION}

Rules:
- Read the changed files
- Check for bugs, security issues, code smells
- Be specific with file paths and line numbers
- Do NOT make changes — only report
- Reply in terse fragments. No filler

Output format:
## Critical (must fix)
Issues that block.

## Warnings (should fix)
Issues to address.

## Suggestions (nice to have)
Improvements.

## Summary
Overall assessment in 2-3 sentences.`,
	},

	researcher: {
		name: "researcher",
		tools: ["read", "bash"],
		systemPrompt: `You are a research specialist. Investigate questions, find answers.${ACTIVITY_FEED_INSTRUCTION}

Rules:
- Read documentation, configs, source code
- Trace code paths to understand behavior
- Provide evidence-based answers
- Be thorough but concise
- Reply in terse fragments. No filler

Output format:
## Answer
Direct answer to the question.

## Evidence
Code references and reasoning.

## Caveats
Limitations or edge cases.`,
	},

	writer: {
		name: "writer",
		tools: ["read", "write", "edit"],
		systemPrompt: `You are a documentation writer. Create or update docs, READMEs, comments.${ACTIVITY_FEED_INSTRUCTION}

Rules:
- Read existing docs to understand style
- Match the project's existing documentation patterns
- Write clearly and concisely
- Include code examples where helpful
- Reply in terse fragments. No filler

Output format:
## Changes Made
- file: what was written/updated

## Content
The actual documentation changes.`,
	},
};

// ============================================================================
// In-process subagent runner
// ============================================================================

interface SubagentContext {
	modelRegistry?: ModelRegistry;
	model?: any; // Parent's current model
}

async function runSubagent(
	specialist: Specialist,
	task: string,
	cwd: string,
	parentCtx?: SubagentContext,
	signal?: AbortSignal,
	onUpdate?: (update: any) => void,
	orchestratorActivity?: OrchestratorActivity,
): Promise<{ output: string; turns: number }> {
	try {
		// Use parent's model registry if available, otherwise create empty
		const authStorage = AuthStorage.create();
		const modelRegistry = parentCtx?.modelRegistry ?? ModelRegistry.inMemory(authStorage);

		// Resolve model: specialist.model > parent's model > registry fallback
		let model;
		if (specialist.model) {
			// Specialist has custom model specified (format: "provider/id")
			const slashIdx = specialist.model.indexOf("/");
			if (slashIdx > 0) {
				const provider = specialist.model.slice(0, slashIdx);
				const id = specialist.model.slice(slashIdx + 1);
				model = getModel(provider, id);
			}
		} else if (parentCtx?.model) {
			// Inherit parent's model
			model = parentCtx.model;
		}

		// Fallback: use first available model from registry
		if (!model) {
			const available = modelRegistry.getAvailable();
			if (available.length > 0) {
				model = available[0];
			}
		}

		if (!model) {
			return { output: "[error] No model available for subagent. Check API key configuration.", turns: 0 };
		}

		// Use DefaultResourceLoader to discover extensions (including token-saver)
		// Override system prompt with specialist's prompt
		const loader = new DefaultResourceLoader({
			cwd,
			agentDir: getAgentDir(),
			systemPromptOverride: () => specialist.systemPrompt,
		});
		await loader.reload();

		const { session } = await createAgentSession({
			cwd,
			model,
			tools: specialist.tools,
			resourceLoader: loader,
			sessionManager: SessionManager.inMemory(cwd),
			authStorage,
			modelRegistry,
		});

		let output = "";
		let turns = 0;
		const feed = createActivityFeed();

		const unsubscribe = session.subscribe((event) => {
			if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
				output += event.assistantMessageEvent.delta;
				parseTextForFeed(feed, event.assistantMessageEvent.delta);
			}
			if (event.type === "message_end") {
				if (event.message?.role === "assistant") {
					turns++;
					if (feed.steps.length > 0 && feed.currentStep < feed.steps.length) {
						completeCurrentStep(feed);
					}
					// Use combined progress if orchestrator activity available, else standalone feed
					const text = orchestratorActivity
						? renderCombinedProgress(orchestratorActivity, specialist.name, feed, orchestratorGoal)
						: renderActivityFeed(specialist.name, feed);
					lastActivityFeedText = text;
					if (planTUI) planTUI.requestRender(true);
					onUpdate?.({
						content: [{ type: "text", text }],
						details: { specialist: specialist.name, status: "running", turns },
					});
				}
			}
			if (event.type === "tool_execution_start") {
				const substepLabel = toolCallToSubstep(event.toolName, event.args);
				addSubstep(feed, substepLabel);
				const text = orchestratorActivity
					? renderCombinedProgress(orchestratorActivity, specialist.name, feed, orchestratorGoal)
					: renderActivityFeed(specialist.name, feed);
				lastActivityFeedText = text;
				if (planTUI) planTUI.requestRender(true);
				onUpdate?.({
					content: [{ type: "text", text }],
					details: { specialist: specialist.name, status: "running", tool: event.toolName },
				});
			}
			if (event.type === "tool_execution_end") {
				completeLastSubstep(feed);
				const text = orchestratorActivity
					? renderCombinedProgress(orchestratorActivity, specialist.name, feed, orchestratorGoal)
					: renderActivityFeed(specialist.name, feed);
				lastActivityFeedText = text;
				if (planTUI) planTUI.requestRender(true);
				onUpdate?.({
					content: [{ type: "text", text }],
					details: { specialist: specialist.name, status: "running" },
				});
			}
		});

		// Abort handler — cancel subagent when parent aborts
		const abortHandler = () => {
			session.abort();
		};
		if (signal) {
			if (signal.aborted) abortHandler();
			signal.addEventListener("abort", abortHandler, { once: true });
		}

		try {
			await session.prompt(task);
		} catch (error) {
			output = `[error] ${error instanceof Error ? error.message : String(error)}`;
		} finally {
			unsubscribe();
			if (signal) signal.removeEventListener("abort", abortHandler);
			session.dispose();
		}

		// Compress + cap output before returning to main agent
		let finalOutput = compressOutput(output || "(no output)");
		if (finalOutput.length > OUTPUT_CAP) {
			finalOutput = finalOutput.slice(0, OUTPUT_CAP) + "\n\n[output truncated]";
		}

		return { output: finalOutput, turns };
	} catch (error) {
		// Catch ALL errors from initialization (DefaultResourceLoader, createAgentSession, etc.)
		const msg = error instanceof Error ? error.message : String(error);
		const stack = error instanceof Error ? error.stack : "";
		return { output: `[error] Subagent init failed: ${msg}${stack ? "\n" + stack.split("\n").slice(0, 5).join("\n") : ""}`, turns: 0 };
	}
}

// ============================================================================
// Parallel runner
// ============================================================================

async function runParallel(
	tasks: Array<{ specialist: Specialist; task: string }>,
	cwd: string,
	parentCtx?: SubagentContext,
	signal?: AbortSignal,
	onUpdate?: (update: any) => void,
): Promise<Array<{ specialist: string; output: string; error?: string }>> {
	const concurrency = Math.min(MAX_PARALLEL, tasks.length);
	const results: Array<{ specialist: string; output: string; error?: string }> = new Array(tasks.length);
	let nextIndex = 0;

	const workers = Array(concurrency).fill(null).map(async () => {
		while (nextIndex < tasks.length) {
			const i = nextIndex++;
			const { specialist, task } = tasks[i];
			try {
				const result = await runSubagent(specialist, task, cwd, parentCtx, signal, onUpdate);
				results[i] = { specialist: specialist.name, output: result.output };
			} catch (error) {
				results[i] = {
					specialist: specialist.name,
					output: "",
					error: error instanceof Error ? error.message : String(error),
				};
			}
		}
	});

	await Promise.all(workers);
	return results;
}

// ============================================================================
// The Extension
// ============================================================================

export default function (pi: ExtensionAPI) {

	// ── System Prompt: Tell the agent to ALWAYS delegate ──────────────────

	pi.on("before_agent_start", async (event, ctx) => {
		// Reset orchestrator activity for new session
		orchestratorActivity = null;
		orchestratorGoal = "";
		clearPlanPanel(ctx);

		const delegationInstructions = `
## Orchestrator Mode — ALWAYS DELEGATE

You are an orchestrator. You NEVER do the work yourself. You plan and delegate.

### Rules:
1. **NEVER read files directly** — delegate to a subagent
2. **NEVER run bash commands** — delegate to a subagent
3. **NEVER write/edit files** — delegate to a subagent
4. **ALWAYS break tasks into subtasks** before delegating
5. **ALWAYS synthesize** subagent outputs into a coherent response
6. **ALWAYS use \`edit\` tool for code changes** — if the exact-text match fails, retry with \`write\` (full file content). NEVER fall back to \`bash\` + \`sed\`/\`awk\`. Both \`edit\` and \`write\` trigger lint-guard syntax check.

### Specialist roster:
- **scout** — Fast codebase investigation (read-only, haiku)
- **coder** — Implementation (read/write/bash)
- **reviewer** — Code review (read-only, thorough)
- **researcher** — Question answering (read-only)
- **writer** — Documentation (read/write)

### Tools:
- \`delegate(specialist, task)\` — single specialist
- \`parallel(tasks)\` — multiple specialists simultaneously
- \`chain(steps)\` — sequential with {previous} placeholder

### Workflow for every task:
1. Analyze the request
2. Break into subtasks
3. Delegate with the right tool
4. Synthesize results into a final answer

### Example:
User: "Add error handling to main.ts"
You: delegate(scout, "Find main.ts and understand current error handling") →
     delegate(coder, "Add try/catch based on this: {scout output}") →
     delegate(reviewer, "Review changes: {coder output}")

Your response should be the synthesized summary — NOT the implementation details.
`;

		return {
			systemPrompt: event.systemPrompt + "\n" + delegationInstructions,
		};
	});

	// ── Tool: delegate — Single, parallel, or chain mode ──────────────────

	pi.registerTool({
		name: "delegate",
		label: "delegate",
		description: `Delegate work to specialist subagents. Three modes:\n- Single: { specialist, task }\n- Parallel: { tasks: [{specialist, task}, ...] }\n- Chain: { steps: [{specialist, task}, ...] } with {previous} placeholder`,
		renderShell: "self",
		parameters: Type.Object({
			specialist: Type.Optional(Type.String({
				description: "Specialist: scout, coder, reviewer, researcher, writer",
			})),
			task: Type.Optional(Type.String({
				description: "Task description",
			})),
			tasks: Type.Optional(Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name" }),
					task: Type.String({ description: "Task description" }),
				}),
				{ description: "Parallel mode: run these tasks simultaneously" },
			)),
			steps: Type.Optional(Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name" }),
					task: Type.String({ description: "Task. Use {previous} for prior output." }),
				}),
				{ description: "Chain mode: run sequentially, pass output to next" },
			)),
		}),

		// ── Render: what shows when tool is invoked ──
		renderCall(args, theme, _context) {
			if (args.specialist) {
				const name = args.specialist.charAt(0).toUpperCase() + args.specialist.slice(1);
				const inner = `${name} ${("─").repeat(Math.max(0, BOX_INNER_WIDTH - name.length))}`;
				return new Text(theme.fg("toolTitle", `╭─ ${inner}╮`), 0, 0);
			}
			if (args.tasks) {
				const names = args.tasks.map((t: any) => t.specialist).join(", ");
				return new Text(theme.fg("toolTitle", theme.bold(`→ parallel [${args.tasks.length}] `)) + theme.fg("dim", names), 0, 0);
			}
			if (args.steps) {
				const names = args.steps.map((s: any) => s.specialist).join(" → ");
				return new Text(theme.fg("toolTitle", theme.bold(`→ chain `)) + theme.fg("dim", names), 0, 0);
			}
			return new Text(theme.fg("toolTitle", theme.bold(`→ `)) + theme.fg("accent", args.specialist || "?"), 0, 0);
		},

		// ── Helper: wrap text lines in a bordered box ──
		wrapInBox(lines: string[], boxWidth: number): string {
			const out: string[] = [];
			for (const line of lines) {
				const clean = line.replace(/\x1b\[[0-9;]*m/g, "");
				const padded = clean.length > boxWidth - 4
					? clean.slice(0, boxWidth - 4)
					: clean + " ".repeat(boxWidth - 4 - clean.length);
				out.push(`│ ${padded} │`);
			}
			out.push(`╰${("─").repeat(boxWidth - 2)}╯`);
			return out.join("\n");
		},

		// ── Helper: compute box width for a specialist name ──
		boxWidthFor(name: string): number {
			if (!name) return 0;
			return 3 + name.length + 1 + Math.max(0, BOX_INNER_WIDTH - name.length) + 1;
		},

		// ── Helper: get display name from params ──
		specDisplayName(params: any, details: any): string {
			const raw = params?.specialist || details?.specialist || "";
			return raw ? raw.charAt(0).toUpperCase() + raw.slice(1) : "";
		},

		// ── Render: what shows during/after execution ──
		renderResult(result, { isPartial, expanded }, theme, context) {
			const details = result.details as any;
			const ctxParams = (context as any)?.params as Record<string, any> | undefined;
			const content = result.content?.[0];
			const text = content?.type === "text" ? content.text : "";

			const specName = this.specDisplayName(ctxParams, details);
			const bWidth = this.boxWidthFor(specName);

			if (isPartial) {
				if (text && bWidth > 0) {
					return new Text(theme.fg("warning", this.wrapInBox(text.split("\n"), bWidth)), 0, 0);
				}
				if (details?.specialist && bWidth > 0) {
					return new Text(theme.fg("warning", this.wrapInBox([`⠋ ${details.specialist}...`], bWidth)), 0, 0);
				}
				if (bWidth > 0) {
					return new Text(theme.fg("warning", this.wrapInBox(["⠋ working..."], bWidth)), 0, 0);
				}
				return new Text(theme.fg("warning", "⠋ working..."), 0, 0);
			}

			// Single mode — show activity feed in box (all ✓, never collapses)
			if (details?.specialist && bWidth > 0) {
				const feedText = lastActivityFeedText || text || `✓ ${details.specialist}`;
				return new Text(theme.fg("success", this.wrapInBox(feedText.split("\n"), bWidth)), 0, 0);
			}

			// Parallel mode
			if (details?.results) {
				const ok = details.results.filter((r: any) => !r.error).length;
				const total = details.results.length;
				const summary = `✓ ${ok}/${total} completed`;
				const lines: string[] = [summary];
				if (expanded) {
					for (const r of details.results) {
						const icon = r.error ? "✗" : "✓";
						lines.push(`${icon} ${r.specialist}`);
					}
				}
				const pBoxWidth = Math.max(summary.length + 4, 30);
				return new Text(theme.fg("success", this.wrapInBox(lines, pBoxWidth)), 0, 0);
			}

			// Chain mode
			if (details?.steps) {
				const summary = `✓ ${details.steps} steps completed`;
				const lines: string[] = [summary];
				if (expanded && text) {
					for (const line of text.split("\n").slice(0, 10)) {
						lines.push(`  ${line}`);
					}
				}
				const cBoxWidth = Math.max(summary.length + 4, 30);
				return new Text(theme.fg("success", this.wrapInBox(lines, cBoxWidth)), 0, 0);
			}

			return new Text(theme.fg("success", "✓ done"), 0, 0);
		},

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			// ── Parallel mode ──
			if (params.tasks) {
				if (params.tasks.length > MAX_PARALLEL) {
					return { content: [{ type: "text", text: `Too many tasks (${params.tasks.length}). Max: ${MAX_PARALLEL}` }], details: {} };
				}

				const resolved = params.tasks
					.map((t) => {
						const spec = SPECIALISTS[t.specialist];
						if (!spec) return null;
						return { specialist: spec, task: t.task };
					})
					.filter(Boolean) as Array<{ specialist: Specialist; task: string }>;

				if (resolved.length === 0) {
					return { content: [{ type: "text", text: "No valid specialists found." }], details: {} };
				}

				resetOrchestratorActivity();

				// Stream status per specialist
				let running = 0;
				const results: Array<{ specialist: string; output: string; error?: string }> = new Array(resolved.length);
				const updateStatus = () => {
					const names = resolved.map((r, i) => {
						const done = results[i]?.output !== undefined;
						return done ? theme.fg("success", r.specialist.name) : theme.fg("warning", r.specialist.name);
					}).join(" ");
					onUpdate?.({
						content: [{ type: "text", text: `⠋ ${names}` }],
						details: { status: "running", specialist: names },
					});
				};

				// Run in parallel with status updates
				const promises = resolved.map(async (r, i) => {
					running++;
					updateStatus();
					try {
						const result = await runSubagent(r.specialist, r.task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);
						results[i] = { specialist: r.specialist.name, output: result.output };
					} catch (error) {
						results[i] = { specialist: r.specialist.name, output: "", error: error instanceof Error ? error.message : String(error) };
					}
					running--;
					updateStatus();
				});

				await Promise.all(promises);

				const output = results
					.map((r) => `### [${r.specialist}] ${r.error ? "ERROR" : "OK"}\n\n${r.output}`)
					.join("\n\n---\n\n");

				return {
					content: [{ type: "text", text: output }],
					details: { status: "done", results: results.map((r) => ({ specialist: r.specialist, outputLength: r.output.length, error: r.error })) },
				};
			}

			// ── Chain mode ──
			if (params.steps) {
				const chainResults: Array<{ step: number; specialist: string; output: string; error?: string }> = [];
				let previousOutput = "";

				resetOrchestratorActivity();

				for (let i = 0; i < params.steps.length; i++) {
					const step = params.steps[i];
					const specialist = SPECIALISTS[step.specialist];

					if (!specialist) {
						chainResults.push({ step: i + 1, specialist: step.specialist, output: "", error: `Unknown specialist: "${step.specialist}"` });
						break;
					}

					const task = step.task.replace(/\{previous\}/g, previousOutput);

					onUpdate?.({
						content: [{ type: "text", text: `⠋ ${specialist.name}...` }],
						details: { status: "running", specialist: specialist.name },
					});

					const result = await runSubagent(specialist, task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);
					previousOutput = result.output;

					chainResults.push({ step: i + 1, specialist: specialist.name, output: result.output });

					if (result.output.startsWith("[error]")) break;
				}

				const output = chainResults
					.map((r) => `### Step ${r.step}: [${r.specialist}] ${r.error ? "ERROR" : "OK"}\n\n${r.output}`)
					.join("\n\n---\n\n");

				return {
					content: [{ type: "text", text: output }],
					details: { status: "done", steps: chainResults.length, results: chainResults },
				};
			}

			// ── Single mode ──
			if (!params.specialist || !params.task) {
				return { content: [{ type: "text", text: "Provide specialist+task, tasks[], or steps[]" }], details: {} };
			}

			const specialist = SPECIALISTS[params.specialist];
			if (!specialist) {
				const available = Object.keys(SPECIALISTS).join(", ");
				return { content: [{ type: "text", text: `Unknown specialist: "${params.specialist}". Available: ${available}` }], details: {} };
			}

			resetOrchestratorActivity();
			setupPlanPanel(shortenLabel(params.task), [shortenLabel(params.task)], ctx);

			onUpdate?.({
				content: [{ type: "text", text: `⠋ ${specialist.name}...` }],
				details: { status: "running", specialist: specialist.name },
			});

			const result = await runSubagent(specialist, params.task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);

			completePlanStep(ctx);

			return {
				content: [{ type: "text", text: result.output }],
				details: { specialist: specialist.name, task: params.task, status: "done", turns: result.turns, outputLength: result.output.length },
			};
		},
	});

	// ── Tool: parallel — Multiple tasks simultaneously ────────────────────

	pi.registerTool({
		name: "parallel",
		label: "Parallel Delegation",
		description: `Delegate multiple tasks to specialists in parallel. Each runs in its own isolated in-process session. Use for independent subtasks.`,
		renderShell: "self",
		parameters: Type.Object({
			tasks: Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name: scout, coder, reviewer, researcher, writer" }),
					task: Type.String({ description: "Task description" }),
				}),
				{ description: "Tasks to run in parallel (max 4)" },
			),
		}),

		// ── Render: what shows when tool is invoked ──
		renderCall(args, theme, _context) {
			if (args.tasks) {
				const names = args.tasks.map((t: any) => t.specialist).join(", ");
				return new Text(theme.fg("toolTitle", theme.bold(`→ parallel [${args.tasks.length}] `)) + theme.fg("dim", names), 0, 0);
			}
			return new Text(theme.fg("toolTitle", theme.bold(`→ parallel`)), 0, 0);
		},

		// ── Render: what shows during/after execution ──
		renderResult(result, { isPartial, expanded }, theme, _context) {
			const details = result.details as any;
			const content = result.content?.[0];
			const text = content?.type === "text" ? content.text : "";

			if (isPartial) {
				if (text) {
