		renderCall(args, theme, _context) {
			if (args.steps) {
				const names = args.steps.map((s: any) => s.specialist).join(" → ");
				return new Text(theme.fg("toolTitle", theme.bold(`→ chain `)) + theme.fg("dim", names), 0, 0);
			}
			return new Text(theme.fg("toolTitle", theme.bold(`→ chain`)), 0, 0);
		},

