						lines.push(`  ${line}`);
					}
				}
				const cBoxWidth = Math.max(summary.length + 4, 30);
				const out = wrapInBoxStatic(lines, cBoxWidth);
				return new Text(theme.fg("success", out), 0, 0);
			}

			return new Text(theme.fg("success", "✓ done"), 0, 0);
		},

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			const chainResults: Array<{ step: number; specialist: string; output: string; error?: string }> = [];
			let previousOutput = "";

			// Reset and create fresh orchestrator activity
			resetOrchestratorActivity();
			const stepLabels = params.steps.map((s: any) => shortenLabel(s.task));
			setupPlanPanel(orchestratorGoal || stepLabels.join(" → "), stepLabels, ctx);
			const activity = getOrchestratorActivity();
			for (const step of params.steps) {
				addOrchestratorStep(activity, step.task);
			}

			for (let i = 0; i < params.steps.length; i++) {
				const step = params.steps[i];
				const specialist = SPECIALISTS[step.specialist];

				if (!specialist) {
					chainResults.push({
						step: i + 1,
						specialist: step.specialist,
						output: "",
						error: `Unknown specialist: "${step.specialist}"`,
					});
					break;
