				const task = step.task.replace(/\{previous\}/g, previousOutput);

				// Stream orchestrator progress
				onUpdate?.({
					content: [{ type: "text", text: renderOrchestratorActivity(activity, orchestratorGoal) }],
					details: {
						status: "running",
						step: i + 1,
						total: params.steps.length,
						specialist: specialist.name,
					},
				});

				const result = await runSubagent(specialist, task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate, activity);
				previousOutput = result.output;

				// Mark step complete
				completeOrchestratorStep(activity);
				completePlanStep(ctx);

				chainResults.push({
					step: i + 1,
					specialist: specialist.name,
					output: result.output,
				});

				// Stop chain on error output
				if (result.output.startsWith("[error]")) break;
			}

			// Final update
			onUpdate?.({
				content: [{ type: "text", text: renderOrchestratorActivity(activity, orchestratorGoal) }],
				details: { status: "done" },
			});

			const output = chainResults
				.map((r) => {
					const status = r.error ? "ERROR" : "OK";
					return `### Step ${r.step}: [${r.specialist}] ${status}\n\n${r.output}`;
				})
				.join("\n\n---\n\n");

			return {
				content: [{ type: "text", text: output }],
				details: {
					status: "done",
					steps: chainResults.length,
					results: chainResults,
				},
			};
		},
	});

	// ── Command: /orchestrate — manual task trigger ───────────────────────

	pi.registerCommand("orchestrate", {
		description: "Run an orchestrated task with multiple specialists",
		usage: "/orchestrate <task description>",
		handler: async (args, ctx) => {
